//! Launch Interceptor Program — DECIDE (Knight & Leveson, 1986).

use crate::types::{DecideInput, DecideOutput};

const SPEC_PI: f64 = 3.1415926535;

/// Compare two reals using six significant decimal digits (see `spec.md`).
pub fn realcompare(a: f64, b: f64) -> &'static str {
    let ra = round_to_n_significant_digits(a, 6);
    let rb = round_to_n_significant_digits(b, 6);
    if ra < rb {
        "LT"
    } else if ra > rb {
        "GT"
    } else {
        "EQ"
    }
}

fn round_to_n_significant_digits(x: f64, n: u32) -> f64 {
    if x == 0.0 {
        return 0.0;
    }
    if !x.is_finite() {
        return x;
    }
    let neg = x < 0.0;
    let ax = x.abs();
    let exp = ax.log10().floor() as i32;
    let power = 10_f64.powi(n as i32 - 1 - exp);
    let rounded = (ax * power).round() / power;
    if neg {
        -rounded
    } else {
        rounded
    }
}

fn dist(x: &[f64], y: &[f64], i: usize, j: usize) -> f64 {
    let dx = x[j] - x[i];
    let dy = y[j] - y[i];
    (dx * dx + dy * dy).sqrt()
}

fn triangle_area(x: &[f64], y: &[f64], i: usize, j: usize, k: usize) -> f64 {
    let a = (x[j] - x[i]) * (y[k] - y[i]) - (x[k] - x[i]) * (y[j] - y[i]);
    0.5 * a.abs()
}

fn min_enclosing_circle_radius(x: &[f64], y: &[f64], i: usize, j: usize, k: usize) -> f64 {
    let d_ij = dist(x, y, i, j);
    let d_jk = dist(x, y, j, k);
    let d_ik = dist(x, y, i, k);
    let area = triangle_area(x, y, i, j, k);

    if realcompare(area, 0.0) == "EQ" {
        let m = d_ij.max(d_jk).max(d_ik);
        return 0.5 * m;
    }

    fn obtuse_at(
        x: &[f64],
        y: &[f64],
        v: usize,
        p: usize,
        q: usize,
    ) -> bool {
        let vx = x[p] - x[v];
        let vy = y[p] - y[v];
        let wx = x[q] - x[v];
        let wy = y[q] - y[v];
        realcompare(vx * wx + vy * wy, 0.0) == "LT"
    }

    // Obtuse at j → opposite side is (i, k).
    if obtuse_at(x, y, j, i, k) {
        return 0.5 * d_ik;
    }
    if obtuse_at(x, y, i, j, k) {
        return 0.5 * d_jk;
    }
    if obtuse_at(x, y, k, i, j) {
        return 0.5 * d_ij;
    }

    (d_ij * d_jk * d_ik) / (4.0 * area)
}

fn fits_in_circle_radius(
    x: &[f64],
    y: &[f64],
    i: usize,
    j: usize,
    k: usize,
    radius: f64,
) -> bool {
    let r = min_enclosing_circle_radius(x, y, i, j, k);
    let c = realcompare(r, radius);
    c == "LT" || c == "EQ"
}

fn quadrant(x: f64, y: f64) -> u8 {
    let xc = realcompare(x, 0.0);
    let yc = realcompare(y, 0.0);
    if xc == "EQ" && yc == "EQ" {
        return 1;
    }
    if xc == "LT" && yc == "EQ" {
        return 2;
    }
    if xc == "EQ" && yc == "LT" {
        return 3;
    }
    if xc == "EQ" && yc == "GT" {
        return 1;
    }
    if xc == "GT" && yc == "EQ" {
        return 1;
    }
    if xc == "GT" && yc == "GT" {
        return 1;
    }
    if xc == "LT" && yc == "GT" {
        return 2;
    }
    if xc == "LT" && yc == "LT" {
        return 3;
    }
    4
}

/// Perpendicular distance from `p` to the infinite line through `a` and `b`.
fn point_to_line_distance(
    px: f64,
    py: f64,
    ax: f64,
    ay: f64,
    bx: f64,
    by: f64,
) -> f64 {
    let abx = bx - ax;
    let aby = by - ay;
    let apx = px - ax;
    let apy = py - ay;

    if realcompare(abx, 0.0) == "EQ" && realcompare(aby, 0.0) == "EQ" {
        return (apx * apx + apy * apy).sqrt();
    }

    let num = (abx * apy - aby * apx).abs();
    let den = (abx * abx + aby * aby).sqrt();
    num / den
}

fn angle_at_vertex(
    x: &[f64],
    y: &[f64],
    a: usize,
    v: usize,
    c: usize,
) -> Option<f64> {
    if realcompare(x[a], x[v]) == "EQ" && realcompare(y[a], y[v]) == "EQ" {
        return None;
    }
    if realcompare(x[c], x[v]) == "EQ" && realcompare(y[c], y[v]) == "EQ" {
        return None;
    }
    let bax = x[a] - x[v];
    let bay = y[a] - y[v];
    let bcx = x[c] - x[v];
    let bcy = y[c] - y[v];
    let n1 = (bax * bax + bay * bay).sqrt();
    let n2 = (bcx * bcx + bcy * bcy).sqrt();
    if realcompare(n1, 0.0) == "EQ" || realcompare(n2, 0.0) == "EQ" {
        return None;
    }
    let mut cs = (bax * bcx + bay * bcy) / (n1 * n2);
    if cs > 1.0 {
        cs = 1.0;
    } else if cs < -1.0 {
        cs = -1.0;
    }
    Some(cs.acos())
}

fn lic1(x: &[f64], y: &[f64], n: usize, length1: f64) -> bool {
    for i in 0..n - 1 {
        let d = dist(x, y, i, i + 1);
        if realcompare(d, length1) == "GT" {
            return true;
        }
    }
    false
}

fn lic2(x: &[f64], y: &[f64], n: usize, radius1: f64) -> bool {
    for i in 0..n.saturating_sub(2) {
        if !fits_in_circle_radius(x, y, i, i + 1, i + 2, radius1) {
            return true;
        }
    }
    false
}

fn lic3(x: &[f64], y: &[f64], n: usize, epsilon: f64) -> bool {
    let low = SPEC_PI - epsilon;
    let high = SPEC_PI + epsilon;
    for k in 1..n.saturating_sub(1) {
        if let Some(angle) = angle_at_vertex(x, y, k - 1, k, k + 1) {
            if realcompare(angle, low) == "LT" || realcompare(angle, high) == "GT" {
                return true;
            }
        }
    }
    false
}

fn lic4(x: &[f64], y: &[f64], n: usize, area1: f64) -> bool {
    for i in 0..n.saturating_sub(2) {
        let a = triangle_area(x, y, i, i + 1, i + 2);
        if realcompare(a, area1) == "GT" {
            return true;
        }
    }
    false
}

fn lic5(x: &[f64], y: &[f64], n: usize, q_pts: usize, quads: usize) -> bool {
    if q_pts > n {
        return false;
    }
    for start in 0..=n - q_pts {
        let mut seen = [false; 5];
        for i in start..start + q_pts {
            let q = quadrant(x[i], y[i]) as usize;
            seen[q] = true;
        }
        let mut count = 0usize;
        for q in 1..=4 {
            if seen[q] {
                count += 1;
            }
        }
        if count > quads {
            return true;
        }
    }
    false
}

fn lic6(x: &[f64], _y: &[f64], n: usize) -> bool {
    for i in 0..n - 1 {
        let dx = x[i + 1] - x[i];
        if realcompare(dx, 0.0) == "LT" {
            return true;
        }
    }
    false
}

fn lic7(x: &[f64], y: &[f64], n: usize, n_pts: usize, dist_param: f64) -> bool {
    if n < 3 {
        return false;
    }
    if n_pts > n {
        return false;
    }
    for start in 0..=n - n_pts {
        let first = start;
        let last = start + n_pts - 1;
        let fx = x[first];
        let fy = y[first];
        let lx = x[last];
        let ly = y[last];

        if realcompare(fx, lx) == "EQ" && realcompare(fy, ly) == "EQ" {
            for i in start..start + n_pts {
                let d = dist(x, y, i, first);
                if realcompare(d, dist_param) == "GT" {
                    return true;
                }
            }
        } else {
            for i in start + 1..start + n_pts - 1 {
                let d = point_to_line_distance(x[i], y[i], fx, fy, lx, ly);
                if realcompare(d, dist_param) == "GT" {
                    return true;
                }
            }
        }
    }
    false
}

fn lic8(x: &[f64], y: &[f64], n: usize, k_pts: usize, length1: f64) -> bool {
    if n < 3 || n < k_pts + 2 {
        return false;
    }
    let max_i = n - k_pts - 2;
    for i in 0..=max_i {
        let j = i + k_pts + 1;
        let d = dist(x, y, i, j);
        if realcompare(d, length1) == "GT" {
            return true;
        }
    }
    false
}

fn lic9(x: &[f64], y: &[f64], n: usize, a_pts: usize, b_pts: usize, radius1: f64) -> bool {
    if n < 5 {
        return false;
    }
    let span = a_pts + b_pts + 2;
    if n <= span {
        return false;
    }
    let max_i = n - span - 1;
    for i in 0..=max_i {
        let j = i + a_pts + 1;
        let k = i + a_pts + b_pts + 2;
        if !fits_in_circle_radius(x, y, i, j, k, radius1) {
            return true;
        }
    }
    false
}

fn lic10(x: &[f64], y: &[f64], n: usize, c_pts: usize, d_pts: usize, epsilon: f64) -> bool {
    if n < 5 {
        return false;
    }
    let low = SPEC_PI - epsilon;
    let high = SPEC_PI + epsilon;
    let span = c_pts + d_pts + 2;
    if n <= span {
        return false;
    }
    let max_i = n - span - 1;
    for i in 0..=max_i {
        let v = i + c_pts + 1;
        let c = i + c_pts + d_pts + 2;
        if let Some(angle) = angle_at_vertex(x, y, i, v, c) {
            if realcompare(angle, low) == "LT" || realcompare(angle, high) == "GT" {
                return true;
            }
        }
    }
    false
}

fn lic11(x: &[f64], y: &[f64], n: usize, e_pts: usize, f_pts: usize, area1: f64) -> bool {
    if n < 5 {
        return false;
    }
    let span = e_pts + f_pts + 2;
    if n <= span {
        return false;
    }
    let max_i = n - span - 1;
    for i in 0..=max_i {
        let j = i + e_pts + 1;
        let k = i + e_pts + f_pts + 2;
        let a = triangle_area(x, y, i, j, k);
        if realcompare(a, area1) == "GT" {
            return true;
        }
    }
    false
}

fn lic12(x: &[f64], _y: &[f64], n: usize, g_pts: usize) -> bool {
    if n < 3 || n < g_pts + 2 {
        return false;
    }
    let max_i = n - g_pts - 2;
    for i in 0..=max_i {
        let j = i + g_pts + 1;
        let dx = x[j] - x[i];
        if realcompare(dx, 0.0) == "LT" {
            return true;
        }
    }
    false
}

fn lic13(x: &[f64], y: &[f64], n: usize, k_pts: usize, length1: f64, length2: f64) -> bool {
    if n < 3 || n < k_pts + 2 {
        return false;
    }
    let max_i = n - k_pts - 2;
    let mut gt = false;
    let mut lt = false;
    for i in 0..=max_i {
        let j = i + k_pts + 1;
        let d = dist(x, y, i, j);
        if realcompare(d, length1) == "GT" {
            gt = true;
        }
        if realcompare(d, length2) == "LT" {
            lt = true;
        }
        if gt && lt {
            return true;
        }
    }
    false
}

fn lic14(x: &[f64], y: &[f64], n: usize, a_pts: usize, b_pts: usize, r1: f64, r2: f64) -> bool {
    if n < 5 {
        return false;
    }
    let span = a_pts + b_pts + 2;
    if n <= span {
        return false;
    }
    let max_i = n - span - 1;
    let mut cannot_r1 = false;
    let mut can_r2 = false;
    for i in 0..=max_i {
        let j = i + a_pts + 1;
        let k = i + a_pts + b_pts + 2;
        if !fits_in_circle_radius(x, y, i, j, k, r1) {
            cannot_r1 = true;
        }
        if fits_in_circle_radius(x, y, i, j, k, r2) {
            can_r2 = true;
        }
        if cannot_r1 && can_r2 {
            return true;
        }
    }
    cannot_r1 && can_r2
}

fn lic15(x: &[f64], y: &[f64], n: usize, e_pts: usize, f_pts: usize, area1: f64, area2: f64) -> bool {
    if n < 5 {
        return false;
    }
    let span = e_pts + f_pts + 2;
    if n <= span {
        return false;
    }
    let max_i = n - span - 1;
    let mut gt_a1 = false;
    let mut lt_a2 = false;
    for i in 0..=max_i {
        let j = i + e_pts + 1;
        let k = i + e_pts + f_pts + 2;
        let a = triangle_area(x, y, i, j, k);
        if realcompare(a, area1) == "GT" {
            gt_a1 = true;
        }
        if realcompare(a, area2) == "LT" {
            lt_a2 = true;
        }
        if gt_a1 && lt_a2 {
            return true;
        }
    }
    false
}

fn compute_cmv(input: &DecideInput) -> Vec<bool> {
    let n = input.numpoints;
    let x = &input.x;
    let y = &input.y;
    let p = &input.parameters;

    vec![
        lic1(x, y, n, p.length1),
        lic2(x, y, n, p.radius1),
        lic3(x, y, n, p.epsilon),
        lic4(x, y, n, p.area1),
        lic5(x, y, n, p.q_pts, p.quads),
        lic6(x, y, n),
        lic7(x, y, n, p.n_pts, p.dist),
        lic8(x, y, n, p.k_pts, p.length1),
        lic9(x, y, n, p.a_pts, p.b_pts, p.radius1),
        lic10(x, y, n, p.c_pts, p.d_pts, p.epsilon),
        lic11(x, y, n, p.e_pts, p.f_pts, p.area1),
        lic12(x, y, n, p.g_pts),
        lic13(x, y, n, p.k_pts, p.length1, p.length2),
        lic14(x, y, n, p.a_pts, p.b_pts, p.radius1, p.radius2),
        lic15(x, y, n, p.e_pts, p.f_pts, p.area1, p.area2),
    ]
}

fn lcm_entry(cmv: &[bool], lcm: &str, i: usize, j: usize) -> bool {
    match lcm {
        "NOTUSED" => true,
        "ANDD" => cmv[i] && cmv[j],
        "ORR" => cmv[i] || cmv[j],
        _ => false,
    }
}

fn build_pum(input: &DecideInput, cmv: &[bool]) -> Vec<Vec<bool>> {
    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        pum[i][i] = input.pum_diag[i];
    }
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                continue;
            }
            let s = &input.lcm[i][j];
            pum[i][j] = lcm_entry(cmv, s, i, j);
        }
    }
    pum
}

fn compute_fuv(pum: &[Vec<bool>]) -> Vec<bool> {
    (0..15)
        .map(|i| {
            let diag_false = !pum[i][i];
            let row_all = (0..15).all(|j| pum[i][j]);
            diag_false || row_all
        })
        .collect()
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let cmv = compute_cmv(input);
    let pum = build_pum(input, &cmv);
    let fuv = compute_fuv(&pum);
    let launch = fuv.iter().all(|&v| v);
    DecideOutput {
        cmv,
        pum,
        fuv,
        launch,
    }
}
